def assess(record: dict) -> str:
    required = {"case_id", "lint", "types", "tests", "matrix", "supported"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (record["lint"] and record["types"] and record["tests"]) and record['matrix'] == record['supported'] else 'FAIL_CI_GATE'

valid = {"case_id": "CASO-PIU-044-1A", **{"lint":True,"types":True,"tests":True,"matrix":{"3.11","3.12"},"supported":{"3.11","3.12"}}}
invalid = {"case_id": "CASO-PIU-044-1A", **{"lint":True,"types":False,"tests":True,"matrix":{"3.10","3.12"},"supported":{"3.11","3.12"}}}
incomplete = {**valid}
incomplete.pop("supported")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

def decide(record: dict) -> str:
    required = {'case_id', 'lint', 'matrix', 'supported', 'tests', 'types'}
    missing = sorted(required - record.keys())
    if missing:
        return 'REVIEW_MATRIX'
    meets = (record["lint"] and record["types"] and record["tests"]) and record['matrix'] == record['supported']
    return "CONTINUE" if meets else 'FAIL_CI_GATE'

valid = {"case_id": 'CASO-PIU-044-1A', **{'lint':True, 'types':True, 'tests':True, 'matrix':{'3.11', '3.12'}, 'supported':{'3.11', '3.12'}}}
invalid = {"case_id": 'CASO-PIU-044-1A', **{'lint':False, 'types':True, 'tests':True, 'matrix':{'3.11', '3.12'}, 'supported':{'3.11', '3.12'}}}
uncertain = {k: v for k, v in valid.items() if k != 'supported'}
results = [decide(item) for item in (valid, invalid, uncertain)]
print(*results)

